// Turn the posted HTML string into an in-memory file named index.html (Gotenberg
// requires the Chromium entrypoint to be called index.html). Also carries the
// requested filename through for the response.
const inp = $input.first().json;
const b = inp.body || inp;
const html = (b && b.html) || '';
const filename = (b && b.filename) || 'CWSI_BoardPack.pdf';
if (!html) { throw new Error('No html provided in request body.'); }
const binary = await this.helpers.prepareBinaryData(Buffer.from(html, 'utf8'), 'index.html', 'text/html');
return [{ json: { filename }, binary: { 'index.html': binary } }];

// Return the PDF to the SPA as base64. n8n may store the HTTP binary in memory OR
// on the filesystem (cloud default) - in filesystem mode item.binary.data.data is
// just the storage marker ("filesystem-v2"), NOT the bytes. getBinaryDataBuffer
// fetches the real buffer either way.
const item = $input.first();
if (!item.binary || !item.binary.data) {
  throw new Error('Gotenberg returned no PDF binary (check the GOTENBERG URL / service).');
}
const buff = await this.helpers.getBinaryDataBuffer(0, 'data');
if (!buff || !buff.length) { throw new Error('Empty PDF buffer from Gotenberg.'); }
return [{ json: { pdfBase64: buff.toString('base64'), filename: item.json.filename || 'CWSI_BoardPack.pdf' } }];
